import { useNavigate } from 'react-router-dom';
import MobileStatusBar from '../components/MobileStatusBar';

import plantsImage from '../assets/plants.jpeg';
import facebookIcon from '../assets/facebook.jpeg';
import googleIcon from '../assets/google.jpeg';
import emailIcon from '../assets/email.jpeg';
import phoneIcon from '../assets/phone.jpeg';

export default function Welcome() {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen bg-[#efefef] flex items-center justify-center px-4">
      <div className="w-[390px] min-h-[844px] bg-[#efefef] px-[10px] pt-[10px] pb-[16px] flex flex-col">
        {/* Reusable iPhone-like status bar */}
        <MobileStatusBar />

        {/* Main welcome content */}
        <div className="flex-1 flex flex-col items-center">
          <div className="mt-[118px] w-full flex justify-center">
            <img
              src={plantsImage}
              alt="Plants illustration"
              className="w-[225px] object-contain select-none"
            />
          </div>

          <h1 className="mt-[8px] text-[24px] leading-none font-bold text-black">
            Welcome to APP
          </h1>

          <div className="mt-auto w-full px-[2px]">
            {/* Divider title */}
            <div className="flex items-center justify-center gap-[10px]">
              <div className="h-[1px] flex-1 bg-[#6f6f6f]" />
              <span className="text-[15px] font-medium text-black">Log in with</span>
              <div className="h-[1px] flex-1 bg-[#6f6f6f]" />
            </div>

            {/* Social icons row */}
            <div className="mt-[18px] flex items-center justify-center gap-[28px]">
              <img
                src={facebookIcon}
                alt="Facebook"
                className="h-[38px] w-[38px] object-contain"
              />
              <img
                src={googleIcon}
                alt="Google"
                className="h-[38px] w-[38px] object-contain"
              />
              <img
                src={emailIcon}
                alt="Email"
                className="h-[38px] w-[38px] object-contain"
              />
              <img
                src={phoneIcon}
                alt="Phone"
                className="h-[38px] w-[38px] object-contain"
              />
            </div>

            {/* Primary action */}
            <button
              type="button"
              onClick={() => navigate('/customer-login')}
              className="mt-[18px] h-[42px] w-full rounded-[8px] bg-[#cfcfcf] text-[18px] font-semibold text-white"
            >
              Get Started
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
